#!/usr/bin/env node
/**
 * Session 7: 93 MC + 7 R/F-Fragen (Recht).
 * R/F-Fragen: aussagen ohne IDs → teilerklaerungen = [] (Spec-Konvention).
 */
import fs from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const OUT = path.join(__dirname, 'fragen-updates.jsonl')
const STATE = path.join(__dirname, 'state.json')

const updates = [
  { id: 'cd1cec47-0cc5-4c1a-85b0-85e23a90722b', fachbereich: 'Recht', musterlosung: 'Jonas hat den Mangel gemeldet, eine Frist gesetzt, und der Vermieter hat nicht gehandelt. Eine defekte Geschirrspülmaschine ist kein gewöhnlicher Unterhalt — ein Fachmann ist nötig. Ihm stehen nun alle vier Rechte aus Art. 259a–259i OR zu: Ersatzvornahme, Mietzinsreduktion, Schadenersatz oder Mietzinshinterlegung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Hinterlegung — vier parallele Rechte stehen zur Verfügung.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Frist ist bereits abgelaufen — keine weitere Fristsetzung nötig.' }, { feld: 'optionen', id: 'opt-2', text: 'Jonas ist weiter als «Mangel entdeckt» — Vermieter hat Frist verstreichen lassen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Vier Optionen — Beseitigung, Reduktion, Schadenersatz, Hinterlegung.' } ] },
  { id: 'cd91bbe7-bf09-41b1-a64d-d7bdde5cce20', fachbereich: 'Recht', musterlosung: 'Hansli ist 16, urteilsfähig und unmündig — also beschränkt handlungsunfähig (Art. 19 ZGB). Er braucht grundsätzlich die Zustimmung seines gesetzlichen Vertreters. Das zweckgebundene Geldgeschenk des Vaters für einen Töffli-Kauf gilt als stillschweigende Zustimmung im Voraus. Hansli kann das Töffli alleine kaufen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Mündigkeitsalter 18 — gilt aber nicht als Voraussetzung für jedes Geschäft.' }, { feld: 'optionen', id: 'opt-1', text: 'Ein Töffli ist nicht geringfügig — die Ausnahme greift nicht. Die Zustimmung kommt über den Zweck des Geldgeschenks.' }, { feld: 'optionen', id: 'opt-2', text: 'Unmündige dürfen nicht frei über Geld verfügen — nur über Lohn eigener Arbeit (Art. 323 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Zweckgebundenes Geldgeschenk = stillschweigende Zustimmung zum Kauf.' } ] },
  { id: 'ce62c932-1aa6-414f-ace4-bdf0eee2dfd7', fachbereich: 'Recht', musterlosung: 'Die Neuerung (Novation) nach OR 116 ist die Tilgung einer alten Schuld durch Begründung einer neuen Schuld. Die alte Obligation erlischt, eine neue tritt an ihre Stelle. Beispiel: Eine Darlehensschuld wird durch Ausstellung eines Wechsels ersetzt. Die Neuerung muss klar gewollt sein — blosse Ergänzungen bewirken keine Novation.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das wäre die Zession (Forderungsübertragung) — andere Rechtsinstitut.' }, { feld: 'optionen', id: 'opt-1', text: 'Fristverlängerung ändert die Obligation nicht — keine Novation.' }, { feld: 'optionen', id: 'opt-2', text: 'Teilzahlung erlöscht die Schuld nur anteilig — keine Novation.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Alte Schuld erlischt, neue entsteht an ihre Stelle (OR 116).' } ] },
  { id: 'cf0bd962-8ca8-43e7-b8a5-af035d302b10', fachbereich: 'Recht', musterlosung: 'Der erste Schritt bei Nachbarschaftskonflikten sollte immer das direkte Gespräch sein — viele Konflikte lösen sich so. Führt dies nicht zum Ziel, kann der Mieter die Verwaltung oder den Vermieter informieren, der nach Art. 257f OR abmahnen kann. Weitere Schritte: Anzeige bei der Polizei oder Zivilklage.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Zuerst Gespräch — niederschwellige und wirksame Erstmassnahme.' }, { feld: 'optionen', id: 'opt-1', text: 'Kündigung wäre drastisch und unverhältnismässig als erster Schritt.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Vermieter ist nicht Störer — keine Klage gegen ihn.' }, { feld: 'optionen', id: 'opt-3', text: 'Polizei erst bei wiederholten schweren Verstössen oder akuten Bedrohungen.' } ] },
  { id: 'cf160236-b03e-4310-9ae4-bd2d07e0f8fc', fachbereich: 'Recht', musterlosung: 'Die Einteilung richtet sich nach der angedrohten Höchststrafe (Art. 10 StGB). Diebstahl (Art. 139 Abs. 1 StGB) ist mit Freiheitsstrafe bis zu 5 Jahren bedroht — das ist mehr als 3 Jahre, also ein Verbrechen (Art. 10 Abs. 2 StGB). Dass alternativ auch Geldstrafe möglich ist, ändert nichts — massgebend ist die Höchststrafe.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Alternative Geldstrafe macht es nicht zum Vergehen — Höchststrafe zählt.' }, { feld: 'optionen', id: 'opt-1', text: 'Richtig, aber aus dem falschen Grund — massgebend ist die angedrohte Höchststrafe.' }, { feld: 'optionen', id: 'opt-2', text: 'Übertretungen werden nur mit Busse bestraft — nicht Diebstahl.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Verbrechen, da Freiheitsstrafe bis 5 Jahre möglich (>3 Jahre).' } ] },
  { id: 'cf5038a7-bdd5-454a-b29e-9e5e201146e7', fachbereich: 'Recht', musterlosung: 'Beschränkt Handlungsunfähige dürfen in drei Ausnahmefällen ohne Zustimmung handeln (Art. 19 Abs. 2 und Art. 19c ZGB): (1) Erlangen unentgeltlicher Vorteile (z.B. Geschenke ohne Folgekosten), (2) geringfügige Angelegenheiten des täglichen Lebens (z.B. Busbillett), (3) Ausübung höchstpersönlicher Rechte. Ein Autokauf fällt unter keine dieser Ausnahmen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Unentgeltliche Vorteile (Art. 19 Abs. 2 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Geringfügige Angelegenheiten des täglichen Lebens (Art. 19 Abs. 2 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Höchstpersönliche Rechte (Art. 19c ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Autokauf ist weder geringfügig noch unentgeltlich — braucht Zustimmung.' } ] },
  { id: 'cfd25ac3-fae1-4101-ad93-b54c84d5afe0', fachbereich: 'Recht', musterlosung: 'Treu und Glauben (Art. 2 Abs. 1 ZGB) verlangt ehrliches und faires Verhalten in der Rechtsausübung. Umgehungsgeschäfte (Maklervertrag aushöhlen), widersprüchliches Verhalten (venire contra factum proprium) und bewusstes Verstreichenlassen von Klagefristen sind Verstösse. Fristgerechte Vertragserfüllung ist dagegen vertragskonform.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Umgehung des Maklervertrags verstösst gegen Treu und Glauben.' }, { feld: 'optionen', id: 'opt-1', text: 'Fristgerechte Zahlung ist vertragsgerecht — kein Verstoss.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Widersprüchliches Verhalten (eigene Zustimmung später anfechten).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Absichtliches Hinhalten bis Fristablauf = Rechtsmissbrauch.' } ] },
  { id: 'd083c51d-6f1e-4a46-912c-55ba1bf3a5ea', fachbereich: 'Recht', musterlosung: 'Die Polizei stützte sich im Fall «Es darf weggewiesen werden» auf Art. 29b (heute Art. 29) des kantonalen Polizeigesetzes des Kantons Bern. Dieser erlaubt die vorübergehende Wegweisung oder Fernhaltung von Personen, wenn sie die öffentliche Sicherheit und Ordnung gefährden oder stören. Art. 36 BV regelt allgemein die Einschränkungsvoraussetzungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Art. 29b PolG BE als konkrete gesetzliche Grundlage.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 36 BV ist Prüfrahmen für Einschränkungen — nicht selbst Ermächtigungsgrundlage.' }, { feld: 'optionen', id: 'opt-2', text: 'Das StGB regelt strafrechtliche Sanktionen — nicht polizeiliche Wegweisung.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 10 BV garantiert die persönliche Freiheit — ist nicht Grundlage für Einschränkung.' } ] },
  { id: 'd09c9c91-1560-48d0-a2a4-860e63553dae', fachbereich: 'Recht', musterlosung: 'OR 336c und 336d nennen Kündigungssperrfristen bei Schwangerschaft (inkl. 16 Wochen nach Niederkunft), Militär-/Zivildienst und Krankheit/Unfall (zeitlich gestaffelt). Diese Sperrfristen schützen Arbeitnehmer in vulnerablen Lebenssituationen. Eine Kündigung wegen Gewerkschaftsaktivität ist dagegen missbräuchlich (Art. 336 OR), aber kein Sperrfristfall.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Schwangerschaft + 16 Wochen nach Niederkunft (OR 336c).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Militär-/Zivildienst ist Sperrfristgrund (OR 336c).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Krankheit/Unfall mit gestaffelten Fristen (OR 336c).' }, { feld: 'optionen', id: 'opt-3', text: 'Gewerkschaftsaktivität ist missbräuchlich (OR 336), aber nicht Sperrfrist.' } ] },
  { id: 'd0f422fd-5fc1-4635-8f22-f610828ac7cd', fachbereich: 'Recht', musterlosung: 'Die Erfüllungsregeln im OR: Persönliche Erfüllung ist nur bei höchstpersönlichen Leistungen Pflicht (OR 68), bei vertretbaren Leistungen genügt Dritterfüllung. Geldschulden sind Bringschulden zum Gläubiger (OR 74 Abs. 2 Ziff. 1). Die Fälligkeit kann durch Parteivereinbarung abweichend von OR 75 geregelt werden. Der Gläubiger kann die Leistung auch an einen Dritten (Vertreter) leisten lassen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Persönliche Erfüllung nur bei höchstpersönlichen Leistungen (OR 68).' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — Stellvertretung und Drittempfang sind möglich.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Geldschulden = Bringschuld (OR 74 Abs. 2 Ziff. 1).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Abweichende Fälligkeit vertraglich möglich (OR 75 ist dispositiv).' } ] },
  { id: 'd2294995-2b38-4126-a1dc-038566fb7a38', fachbereich: 'Recht', musterlosung: 'Art. 3 ZGB regelt den guten Glauben: Wo das Gesetz eine Rechtswirkung an den guten Glauben knüpft, wird dieser vermutet (Abs. 1). Wer bei der gebotenen Aufmerksamkeit nicht gutgläubig sein konnte, kann sich nicht darauf berufen (Abs. 2). Der gute Glaube wird also geschützt — führt aber zur Beweislastumkehr zulasten der Gegenpartei.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Treu und Glauben regelt Art. 2 Abs. 1 ZGB — nicht Art. 3.' }, { feld: 'optionen', id: 'opt-1', text: 'Beweislast regelt Art. 8 ZGB — nicht Art. 3.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Guter Glaube und Vermutung (Art. 3 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Rechtsmissbrauch regelt Art. 2 Abs. 2 ZGB.' } ] },
  { id: 'd283f8ae-9e70-4346-8a35-eba61ec885a8', fachbereich: 'Recht', musterlosung: 'Nach Art. 35 und 36 ArG gelten für schwangere und stillende Frauen besondere Schutzbestimmungen: Nachtarbeit ist grundsätzlich verboten (mit engen Ausnahmen), die Arbeitszeit ist reduziert, und besondere Ruhezeiten sind einzuhalten. Diese gehen über die allgemeinen Nachtarbeitsregeln hinaus und schützen Mutter und Kind.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die allgemeinen Limits genügen nicht — Schwangere sind besonders geschützt.' }, { feld: 'optionen', id: 'opt-1', text: 'Es bestehen sehr wohl besondere Schutzbestimmungen — Art. 35–36 ArG.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Lohnzuschlag allein genügt nicht — Schwangere brauchen umfassenderen Schutz.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Art. 35–36 ArG — spezielle Schutzregelungen für Schwangere und Stillende.' } ] },
  { id: 'd2e1bdb5-ec53-4b6d-95e9-b179f5b87fc1', fachbereich: 'Recht', musterlosung: 'Nach ArG 16–20 erfordert Nachtarbeit (23:00–06:00) einen Lohnzuschlag von mindestens 25% (dauerhaft oder regelmässig wiederkehrend) bzw. eine Zeitgutschrift von 10%. Bei Sonntagsarbeit kommt ein Zuschlag von 50% dazu. Der Zuschlag ist zwingend und soll die erhöhten gesundheitlichen Belastungen ausgleichen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Schriftliche Zustimmung hebt zwingenden Nachtzuschlag nicht auf.' }, { feld: 'optionen', id: 'opt-1', text: 'Nachtarbeit ist nicht generell verboten — nur bewilligungs- und zuschlagspflichtig.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 25% Zuschlag (bzw. 10% Zeitgutschrift), Sonntag 50% nach ArG 16–20.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine gleiche Arbeitszeit nachts — gesundheitsbedingte Sonderregeln.' } ] },
  { id: 'd3187226-108d-4293-a347-1d2794a9fbe2', fachbereich: 'Recht', musterlosung: 'Vorsatz nach Art. 12 Abs. 2 StGB liegt vor, wenn der Täter die Handlung mit Wissen und Willen ausführt — er will den Taterfolg. Fahrlässigkeit nach Art. 12 Abs. 3 StGB liegt vor, wenn der Täter eine Sorgfaltspflicht verletzt. Vorsatz setzt keine Planung voraus — auch spontane bewusste Taten können vorsätzlich sein.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beides gibt es bei allen Deliktsarten — nicht nur Verbrechen oder Vergehen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Wissen + Willen = Vorsatz, Sorgfaltspflichtverletzung = Fahrlässigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Beide Formen sind strafbar — nur wenn das jeweilige Delikt sie vorsieht.' }, { feld: 'optionen', id: 'opt-3', text: 'Vorsatz setzt keine Planung voraus — auch spontan vorsätzliches Handeln.' } ] },
  { id: 'd3d54e7f-2b7a-470d-8a0a-f1edc5fa47e1', fachbereich: 'Recht', musterlosung: 'Der Arbeitnehmer verletzt hier die Geheimhaltungspflicht nach OR 321a Abs. 4. Diese verbietet dem AN, während und nach Beendigung des Arbeitsverhältnisses Geschäfts- und Betriebsgeheimnisse zu verwerten oder anderen mitzuteilen. Die Weitergabe einer geplanten Geschäftsexpansion an die Konkurrenz ist eine schwere Verletzung — möglich sind fristlose Kündigung und Schadenersatz.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Persönliche Arbeitspflicht (OR 321) betrifft die Erbringung der Arbeit, nicht Vertraulichkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Sorgfaltspflicht (OR 321a) ist allgemeiner — hier ist die Geheimhaltung die spezifische Pflicht.' }, { feld: 'optionen', id: 'opt-2', text: 'Weisungsbefolgung (OR 321d) betrifft anderes — Weitergabe ist keine Weisungsfrage.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Schutz von Geschäftsgeheimnissen nach OR 321a Abs. 4.' } ] },
  { id: 'd45cd6b0-1114-40de-8cf1-016a94c30b9c', fachbereich: 'Recht', musterlosung: 'Nach Art. 257f Abs. 3 OR kann der Vermieter bei schwerer Verletzung der Sorgfaltspflicht (fortgesetzte Ruhestörung trotz Abmahnung) ausserordentlich kündigen. Die Kündigungsfrist beträgt mindestens 30 Tage auf Monatsende bei Wohnungen. Die schriftliche Abmahnung ist Voraussetzung — hier bereits zweimal erteilt. Weitere Abmahnungen sind nicht erforderlich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Mindestanzahl an Abmahnungen — eine (schriftliche) reicht nach Rechtsprechung.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein Hausrecht des Störers — Vermieter kann Kündigung aussprechen.' }, { feld: 'optionen', id: 'opt-2', text: 'Kündigung ist möglich — nicht nur Polizei als Möglichkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Ausserordentliche Kündigung, 30 Tage auf Monatsende (Art. 257f Abs. 3 OR).' } ] },
  { id: 'd462c2cb-dee8-477b-b325-4b243332abdc', fachbereich: 'Recht', musterlosung: 'Art. 28 ZGB regelt den zivilrechtlichen Schutz der Persönlichkeit. Jede Verletzung der Persönlichkeit ist widerrechtlich, sofern kein Rechtfertigungsgrund vorliegt (Einwilligung, überwiegendes Interesse, Gesetz). Die verletzte Person kann Beseitigung, Unterlassung, Feststellung, Schadenersatz und Genugtuung verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Art. 28 ZGB — Schutz der Persönlichkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 19 ZGB regelt die beschränkte Handlungsunfähigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 11 ZGB regelt die Rechtsfähigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 14 ZGB regelt die Mündigkeit (18 Jahre).' } ] },
  { id: 'd4860f12-4ebf-43f3-aab2-99b97d9fae52', fachbereich: 'Recht', musterlosung: 'Bei einem städtischen Symbolverbot sind alle vier Prüfpunkte von Art. 36 BV problematisch: (1) Eine Verordnung reicht für einen schweren Eingriff in die Glaubensfreiheit nicht — es braucht ein formelles Gesetz. (2) Das öffentliche Interesse an einem pauschalen Verbot ist zweifelhaft. (3) Mildere Mittel (z.B. Beschränkung auf bestimmte Berufe) wären möglich. (4) Ein umfassendes Verbot tangiert den Kerngehalt der Glaubens- und Gewissensfreiheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Verordnung reicht für schweren Eingriff nicht — formelles Gesetz nötig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Fragliches öffentliches Interesse an pauschalem Verbot.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Mildere Mittel denkbar — Verhältnismässigkeit fraglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Umfassendes Verbot tangiert Kerngehalt der Glaubensfreiheit.' } ] },
  { id: 'd690cf8b-5d26-4668-976d-0be66a342a51', fachbereich: 'Recht', musterlosung: 'Nach Art. 933 ZGB erwirbt der gutgläubige Erwerber Eigentum an einer anvertrauten Sache — auch wenn der Veräusserer nicht berechtigt war. Irina hat das Buch Sylvia anvertraut (ausgeliehen), Sylvia hat es ohne Berechtigung verschenkt, Ruth war gutgläubig. Alle Tatbestandsmerkmale erfüllt — Ruth ist Eigentümerin. Irina kann sich nur an Sylvia halten (Schadenersatz).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Fehlende Berechtigung ist gerade Kerninhalt von Art. 933 — Schutz des Gutgläubigen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Gutgläubigkeit + Anvertrauung = Eigentumserwerb nach Art. 933 ZGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Wert ist für Art. 933 ZGB nicht relevant.' }, { feld: 'optionen', id: 'opt-3', text: 'Auch bei Schenkung greift Art. 933 ZGB — gutgläubige Erwerberin geschützt.' } ] },
  { id: 'd6b3bbce-f4e9-4012-998d-c74850f3bdee', fachbereich: 'Recht', musterlosung: 'Schlagzeug und laute Blasinstrumente können nach Rechtsprechung und Gemeindeverordnungen als unzumutbare Störung gelten — unabhängig von der Tageszeit. Das Spielen kann die Sorgfaltspflicht nach Art. 257f OR verletzen. Bei fortgesetzter Störung trotz schriftlicher Abmahnung kann der Vermieter ausserordentlich kündigen (30 Tage auf Monatsende).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Musizieren ist grundrechtlich geschützt, aber in Mietverhältnissen einschränkbar.' }, { feld: 'optionen', id: 'opt-1', text: 'Musizieren ist nicht generell verboten — nur bei unzumutbarer Lautstärke.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Unzumutbare Lärmbelästigung + Kündigungsrisiko nach Abmahnung.' }, { feld: 'optionen', id: 'opt-3', text: 'Nachtruhe ist nur ein Aspekt — auch tagsüber kann Lärm unzumutbar sein.' } ] },
  { id: 'd6f3c48e-3dc1-4a25-9f11-1c63ce92f526', fachbereich: 'Recht', musterlosung: 'Vreni ist 15 und damit unmündig, aber urteilsfähig — also beschränkt handlungsunfähig (Art. 19 ZGB). Die Ausnahme für rein unentgeltliche Vorteile (Art. 19 Abs. 2 ZGB) greift nicht, da ein Pferd erhebliche laufende Kosten verursacht (Futter, Tierarzt, Stallmiete). Es ist kein rein unentgeltlicher Vorteil. Die Zustimmung des Vaters ist nötig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Falsch — ein Pferd verursacht erhebliche Folgekosten, also nicht rein unentgeltlich.' }, { feld: 'optionen', id: 'opt-1', text: 'Geschenke mit Folgekosten sind nicht «rein unentgeltlich» — Zustimmung nötig.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Unterhaltskosten → kein rein unentgeltlicher Vorteil, Zustimmung nötig.' }, { feld: 'optionen', id: 'opt-3', text: 'Das Kriterium ist nicht «zu teuer», sondern ob Folgekosten entstehen.' } ] },
  { id: 'd7db176e-aee4-4a91-8115-2af4fc6ce04e', fachbereich: 'Recht', musterlosung: 'Nach ZGB 216 erfordert der Grundstückkauf zwingend öffentliche Beurkundung (durch einen Notar). Ein mündlicher Kaufvertrag über ein Grundstück ist nichtig (Art. 11 Abs. 2 OR) — nicht bloss anfechtbar. Die Form ist hier zwingende Gültigkeitsvoraussetzung, nicht nur Beweiszweck. Der Kaufvertrag hat keinerlei Wirkung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Formfreiheit gilt nicht für Grundstücke — Ausnahme nach ZGB 216.' }, { feld: 'optionen', id: 'opt-1', text: 'Einverständnis hebt die Formvorschrift nicht auf — zwingendes Recht.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht anfechtbar, sondern nichtig — stärkere Rechtsfolge.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Öffentliche Beurkundung zwingend, Vertrag nichtig.' } ] },
  { id: 'd80b8576-1b93-4c42-b6ce-7f39fad64ab6', fachbereich: 'Recht', musterlosung: 'Nach OR 66 sind Rückforderungen von Leistungen, die mit dem Ziel eines rechtswidrigen oder unsittlichen Erfolges erbracht wurden, ausgeschlossen. Carl kann die CHF 10\'000 nicht zurückfordern — die Rechtsordnung schützt seine Rückforderung nicht, weil er selbst an der unsittlichen Absprache beteiligt war. Der Grundsatz lautet: «Nemo auditur propriam turpitudinem allegans».', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Hälftelung — OR 66 schliesst Rückforderung vollständig aus.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine ungerechtfertigte Bereicherung — OR 66 ist lex specialis.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Rechtsgrund besteht weiter — nur die Rückforderung ist ausgeschlossen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: OR 66 — keine Rückforderung bei unsittlichem/rechtswidrigem Zweck.' } ] },
  { id: 'd81840cb-22f6-40de-a575-feee30ed27e8', fachbereich: 'Recht', musterlosung: 'Nach Art. 270 OR kann ein neuer Mieter den Anfangsmietzins innert 30 Tagen nach Übernahme der Mietsache bei der Schlichtungsbehörde als missbräuchlich anfechten — wenn er sich in einer persönlichen oder familiären Notlage zum Vertragsabschluss gezwungen sah oder wenn der Mietzins deutlich über dem Vormieter-Niveau liegt ohne wertvermehrende Investitionen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Akzeptanz hindert die Anfechtung nicht — gesetzlicher Schutz.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine einseitige Senkung — der Weg führt über die Schlichtungsbehörde.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 30 Tage nach Übernahme bei der Schlichtungsbehörde anfechten (Art. 270 OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine 12-Monats-Wartefrist — Anfechtungsfrist ist 30 Tage.' } ] },
  { id: 'd8920e4f-d7cb-4cd2-8981-34f4aabec299', fachbereich: 'Recht', musterlosung: 'Dispositives Recht (ergänzendes Recht) gilt nur, wenn die Parteien keine abweichende Vereinbarung getroffen haben. Im Privatrecht sind viele Normen dispositiv — die Parteien können sie vertraglich abändern. Im Gegensatz dazu steht zwingendes Recht, das nicht umgangen werden darf. Beispiel dispositiv: OR 75 (Fälligkeit); Beispiel zwingend: OR 257e (Mietzinsdepot max. 3 Monate).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Alle Gesetze können vom Gesetzgeber geändert werden — dispositiv bedeutet etwas anderes.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre zwingendes Recht — dispositives ist gerade abänderbar.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Berufsrecht — dispositiv bezieht sich auf die Abänderungsmöglichkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Dispositiv = gilt nur ohne abweichende Abmachung der Parteien.' } ] },
  { id: 'd93a28fa-2dc6-4171-9101-2a57fe6e6fa8', fachbereich: 'Recht', musterlosung: 'Der Mietvertrag ist synallagmatisch aufgebaut: Gebrauchsüberlassung gegen Mietzins. Wenn der Mieter seine Hauptpflicht (Mietzinszahlung, Art. 257 OR) verletzt, kann der Vermieter nach Art. 257d OR eine Zahlungsfrist von mindestens 30 Tagen setzen. Bei Nichtzahlung ist eine ausserordentliche Kündigung mit einer Frist von mindestens 30 Tagen auf Monatsende möglich. Eine sofortige Räumung ohne Mahnung ist nicht zulässig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Räumung ohne Mahnung — Art. 257d OR verlangt Zahlungsfrist.' }, { feld: 'optionen', id: 'opt-1', text: 'Der Mietzins ist sehr wohl geschuldet — Gegenseitigkeit des Vertrags.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Zahlungspflicht des Mieters entfällt nicht — nur ihre Geltendmachung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Mahnung + Frist + ausserordentliche Kündigung (Art. 257d OR).' } ] },
  { id: 'd97877c2-6df8-4e10-a3d7-a55be144ffb4', fachbereich: 'Recht', musterlosung: 'Die Hauptpflichten des Mieters nach Art. 257 ff. OR: Mietzinszahlung (Art. 257), sorgfältiger Umgang mit der Mietsache und Rücksichtnahme auf Hausbewohner und Nachbarn (Art. 257f). Die Streichpflicht ist keine Mieterpflicht — kleine Unterhaltsarbeiten (Art. 259) sind die üblichen Belastungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Mietzinszahlung als Hauptpflicht (Art. 257 OR).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Sorgfältiger Umgang mit der Mietsache (Art. 257f OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Rücksichtnahme auf Mitbewohner und Nachbarn (Art. 257f OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine jährliche Streichpflicht — nur gewöhnlicher Unterhalt (Art. 259 OR).' } ] },
  { id: 'd9b668ce-e7fe-41cc-bec9-61210d916648', fachbereich: 'Recht', musterlosung: 'Die Vertragserfüllung kann von beiden Seiten gestört werden: Der Gläubiger kann in Gläubigerverzug geraten (OR 91 ff., Annahmeverweigerung), der Schuldner in Schuldnerverzug (OR 102 ff., verspätete Leistung), Schlechterfüllung (OR 97/197 ff., mangelhafte Leistung) oder Nichterfüllung (OR 97, endgültige Unmöglichkeit). Die Rechtsfolgen variieren je nach Störungsart.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur vom Schuldner — auch der Gläubiger kann in Verzug geraten.' }, { feld: 'optionen', id: 'opt-1', text: 'Dritte Personen sind in der Regel nicht Vertragsparteien.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nur vom Gläubiger — auch der Schuldner kann stören.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Beide Seiten können Störer sein — Gläubiger- oder Schuldnerverzug.' } ] },
  { id: 'd9da3eb8-b1d1-4250-bb3f-49393e44a44d', fachbereich: 'Recht', musterlosung: 'Nach dem Prinzip der relativen Zwingendheit können zwingende Arbeitsrechtsvorschriften nur zugunsten des Arbeitnehmers abgeändert werden — nicht zu seinen Lasten. Eine Verschlechterung ist unwirksam. So kann ein höherer Lohn, mehr Urlaub oder bessere Kündigungsfristen vereinbart werden, aber nicht das Gegenteil.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Abänderungen zugunsten des AN sind zulässig — Schutzprinzip.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Form ist nicht entscheidend — die Richtung der Abänderung zählt.' }, { feld: 'optionen', id: 'opt-2', text: 'Zustimmung von Verbänden ist nicht erforderlich — vertragliche Freiheit im zulässigen Rahmen.' }, { feld: 'optionen', id: 'opt-3', text: 'Zugunsten des AN sind Abänderungen gerade erlaubt — nur zulasten nicht.' } ] },
  { id: 'db221962-bcee-4093-bd45-ad2ec36f44b4', fachbereich: 'Recht', musterlosung: 'Die Allgemeinverbindlichkeit eines GAV (erklärt durch den Bundesrat nach OR 356) bindet alle Betriebe und Arbeitnehmer der betreffenden Branche/Region — unabhängig von Verbandsmitgliedschaft oder Betriebsgrösse. Dies schützt faire Wettbewerbsbedingungen und verhindert «Lohndumping» durch Neu- oder Kleinbetriebe. Die Bäckerei muss die GAV-Bestimmungen einhalten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Betriebsgrösse ist irrelevant — AVE bindet alle.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Befreiung für kleine Betriebe — AVE gilt branchenweit.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: AVE bindet alle Betriebe der Branche.' }, { feld: 'optionen', id: 'opt-3', text: 'AVE ist verfassungskonform — Bundesratskompetenz nach OR 356.' } ] },
  { id: 'db9375d1-71d3-4410-93c6-c71babace419', fachbereich: 'Recht', musterlosung: 'V bleibt Eigentümer des Autos (dingliches Recht nach Art. 641 ZGB). Der Mietvertrag begründet nur ein obligatorisches Recht — M hat einen vertraglichen Anspruch gegenüber V, aber kein dingliches Recht am Auto. M ist unselbständige Besitzerin während der Mietdauer. F hat kein eigenständiges Recht am Auto. Für den Unfallschaden haftet M gegenüber V aus dem Mietvertrag, allenfalls mit Rückgriff auf F.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Miteigentümer — V hat Eigentum, M hat Obligationsrecht.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: V Eigentum, M obligatorisches Recht, F kein Recht.' }, { feld: 'optionen', id: 'opt-2', text: 'F hat kein Besitzrecht übernommen — M bleibt Besitzerin.' }, { feld: 'optionen', id: 'opt-3', text: 'Miete überträgt kein Eigentum — nur Gebrauchsrecht.' } ] },
  { id: 'db9921cd-2e17-45c2-8968-d952ed4a62ca', fachbereich: 'Recht', musterlosung: 'Beim Besitzkonstitut nach Art. 717 ZGB überträgt der Veräusserer das Eigentum an den Erwerber, behält aber die Sache aufgrund eines besonderen Rechtsverhältnisses (z.B. Mietvertrag, Leihe, Hinterlegung) zurück. Beispiel: Sale-and-Lease-back — der Verkäufer least die verkaufte Maschine zurück. Das Besitzkonstitut ersetzt die physische Übergabe.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Eigentum übertragen, Sache via Rechtsverhältnis zurückbehalten.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre Brevi manu traditio — andere Übergabeform.' }, { feld: 'optionen', id: 'opt-2', text: 'Das wäre Traditio longa manu (Schlüsselübergabe) — andere Form.' }, { feld: 'optionen', id: 'opt-3', text: 'Das wäre Hinterlegung an einen Dritten — nicht beim Veräusserer.' } ] },
  { id: 'dbe0ea27-fb00-4caa-9256-96739e255d2d', fachbereich: 'Recht', musterlosung: 'Grundsätzlich haftet, wer schuldhaft einen Schaden verursacht (OR 41). Bei Gefälligkeitshandlungen ohne eigenen Vorteil wird die Haftung nach OR 99 Abs. 2 milder beurteilt — ausser bei grobfahrlässigem oder vorsätzlichem Handeln. Der Gedanke: Wer aus reiner Gefälligkeit hilft, soll nicht für jeden Sorgfaltsfehler voll haften.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Milderte Haftung bei Gefälligkeit ohne eigenen Vorteil (OR 99 Abs. 2).' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht volle Haftung — der Gefälligkeitscharakter mildert.' }, { feld: 'optionen', id: 'opt-2', text: 'Haftungsgrundlage besteht (OR 41) — nur das Mass ist reduziert.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht völlig befreit — bei Verschulden besteht milde Haftung.' } ] },
  { id: 'dc82f879-6443-40f4-b56a-3da229ab1d5a', fachbereich: 'Recht', musterlosung: 'Der Lehrer handelt hier primär aus innerer Überzeugung (Moral) gegen Korruption. Zwar ist Bestechung auch rechtlich verboten (Art. 322ter ff. StGB), aber die Frage zielt auf die Regel, die das Verhalten zuerst und am stärksten beeinflusst. Die moralische Haltung gegen Unrechtes ist der stärkste Antrieb — die Strafandrohung wäre nur zusätzliche Schranke.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Moral ist hier primär wirksam — Recht sekundär.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Moral — innere Überzeugung gegen Korruption.' }, { feld: 'optionen', id: 'opt-2', text: 'Sitte wäre gesellschaftlich erwartet — hier wirkt die innere Haltung stärker.' }, { feld: 'optionen', id: 'opt-3', text: 'Recht greift auch, ist aber nicht der primäre Antrieb.' } ] },
  { id: 'dce39735-e013-411a-a300-2473a1717899', fachbereich: 'Recht', musterlosung: 'Die AEMR von 1948 ist eine Erklärung ohne direkte Rechtsverbindlichkeit — aber moralisch und politisch hoch einflussreich. Die EMRK von 1950 ist dagegen ein völkerrechtlicher Vertrag, der für die Vertragsstaaten (Europaratsmitglieder) verbindlich ist. Zur Durchsetzung besteht der Europäische Gerichtshof für Menschenrechte (EGMR) in Strassburg — auch Einzelpersonen können dort klagen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: EMRK = verbindlicher Vertrag mit EGMR, AEMR = nicht-bindende Erklärung.' }, { feld: 'optionen', id: 'opt-1', text: 'Umgekehrt — AEMR gilt weltweit (UN), EMRK nur in Europa.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — die EMRK hat ähnlichen Rechtebestand, aber mit Durchsetzungsmechanismus.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — AEMR (1948) ist älter als EMRK (1950).' } ] },
  { id: 'dcf07a6e-612d-408f-ad87-0867261912c3', fachbereich: 'Recht', musterlosung: 'Nach Art. 8 ZGB trägt die Beweislast, wer aus einer Tatsache Rechte ableitet. Sabrina will einen Rückzahlungsanspruch geltend machen — sie muss das Darlehen beweisen. Dass kein schriftlicher Vertrag existiert, schliesst den Anspruch nicht aus (Darlehen kann mündlich sein), erschwert aber den Beweis. Zeugenaussagen oder indirekte Indizien können helfen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Amtsermittlung im Zivilprozess — Verhandlungsmaxime.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine umgekehrte Beweislast — Sabrina leitet die Rechte ab.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Sabrina trägt die Beweislast (Art. 8 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Darlehen kann auch mündlich bestehen — Anspruch nicht ausgeschlossen.' } ] },
  { id: 'dcf565d0-4a6e-45b5-8962-7bf35dfb629b', fachbereich: 'Recht', musterlosung: 'Art. 270a OR (Mietzinsherabsetzung) ist eine zwingende Bestimmung zum Schutz des Mieters. Von zwingenden Bestimmungen darf nur zugunsten der schwächeren Partei (Mieter) abgewichen werden — nicht zu ihren Ungunsten. Ein Verzicht auf das Recht zur Mietzinssenkung benachteiligt den Mieter und ist nichtig. Die Klausel entfaltet keine Wirkung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Zusatzklauseln sind grundsätzlich erlaubt — hier geht es um den Inhalt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Nichtig wegen Verstoss gegen zwingende Schutznorm (Art. 270a OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Die Form der Unterschrift heilt den Inhaltsmangel nicht.' }, { feld: 'optionen', id: 'opt-3', text: 'Vertragsfreiheit hat Grenzen — zwingendes Recht.' } ] },
  { id: 'dd8c7421-1f10-438d-a80e-4c01f229a7c8', fachbereich: 'Recht', musterlosung: 'Art. 24 OR unterscheidet verschiedene wesentliche Irrtümer. Erklärungsirrtümer (Abs. 1 Ziff. 1–3): Irrtum über Natur des Vertrags, Person des Vertragspartners oder Umfang der Leistung. Grundlagenirrtum (Abs. 1 Ziff. 4): Irrtum über eine Tatsache, die beide Parteien als notwendige Grundlage angenommen haben. Ein Irrtum über den Preis ist kein eigenständiger Ziff.-4-Tatbestand.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Ziff. 1 — Irrtum über Vertragsnatur (Kauf vs. Schenkung).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Ziff. 2 — Irrtum über die Person des Vertragspartners.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Ziff. 3 — Irrtum über den Umfang der Leistung.' }, { feld: 'optionen', id: 'opt-3', text: 'Ziff. 4 regelt Grundlagenirrtum — Preisirrtum fällt nicht direkt darunter.' } ] },
  { id: 'de16d129-9455-42d6-921a-b77985002324', fachbereich: 'Recht', musterlosung: 'Nach Art. 253 und 256 OR ist der Vermieter verpflichtet, die Mietsache dem Mieter in einem zum vorausgesetzten Gebrauch tauglichen Zustand zu übergeben und in diesem Zustand zu erhalten. Dies ist die Hauptpflicht aus dem synallagmatischen Mietvertrag — als Gegenleistung zum Mietzins. Nebenkosten, Eigentumsübertragung oder jährliche Renovation gehören nicht dazu.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nebenkosten zahlt der Mieter — nicht der Vermieter.' }, { feld: 'optionen', id: 'opt-1', text: 'Eigentum bleibt beim Vermieter — nur Gebrauchsüberlassung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gebrauchsüberlassung + Erhaltung in tauglichem Zustand (Art. 253/256 OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine jährliche Renovationspflicht — nur Erhalt der Tauglichkeit.' } ] },
  { id: 'df520529-f89c-46a4-b6f9-829686351907', fachbereich: 'Recht', musterlosung: 'Die Offizialmaxime gilt im Strafprozess, weil Straftaten nicht nur den Einzelnen, sondern das öffentliche Interesse und die Allgemeinheit betreffen. Der Staat hat die Pflicht, für öffentliche Ordnung und Sicherheit zu sorgen — deshalb verfolgt die Staatsanwaltschaft von Amtes wegen. Im Zivilprozess dagegen gilt die Dispositionsmaxime — die Parteien bestimmen selbst über den Streit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Erfahrung ist nicht das Kriterium — öffentliches Interesse zählt.' }, { feld: 'optionen', id: 'opt-1', text: 'Im Strafprozess steht nicht Privater gegen Privater, sondern Staat gegen Beschuldigten.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Straftaten berühren öffentliches Interesse → Offizialmaxime.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Beschuldigte hat durchaus Rechte (Verteidiger, Unschuldsvermutung).' } ] },
  { id: 'df96f341-f2bc-4910-a533-25e766a7507a', fachbereich: 'Recht', musterlosung: 'Art. 1 Abs. 1 OR regelt den Vertragsabschluss zwischen gleichberechtigten Parteien. Es handelt sich um Privatrecht (Obligationenrecht). Das Unterscheidungskriterium ist nicht die staatliche Vorschrift (das gilt für alles Recht), sondern die Beziehung: koordinativ (gleichberechtigt = Privatrecht) oder subordinativ (Unter-/Überordnung = öffentliches Recht).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht beides — eindeutige Zuordnung zum Privatrecht.' }, { feld: 'optionen', id: 'opt-1', text: 'Staatliche Erlassung macht eine Norm noch nicht zum öffentlichen Recht.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine staatliche Registrierung nötig — formfreie Privatrechtsverträge möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Privatrecht regelt gleichberechtigte Parteien — koordinativ.' } ] },
  { id: 'e08ef18b-cbf3-4187-adda-611b6e61993f', fachbereich: 'Recht', musterlosung: 'Das Deliktsrecht hat drei Hauptfunktionen: (1) Ausgleich unter Rechtssubjekten — der Schädiger muss den Geschädigten entschädigen (Haftungsbegründung/-beschränkung); (2) Schaffung von Kostenwahrheit, insbesondere bei Kausalhaftungen — wer die Gefahr schafft, trägt auch die Kosten; (3) Verhaltenslenkung (Prävention). Bestrafung ist Sache des Strafrechts.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Ausgleich unter Rechtssubjekten als zentrale Funktion.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Kostenwahrheit durch sachgerechte Haftungszuweisung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verhaltenslenkung (Prävention) — Anreiz zur Sorgfalt.' }, { feld: 'optionen', id: 'opt-3', text: 'Bestrafung ist Strafrecht — nicht Zivilrecht.' } ] },
  { id: 'e0b9cbef-024c-4869-b81f-ce092608a786', fachbereich: 'Recht', musterlosung: 'Das Privatrecht umfasst das ZGB mit seinen Teilen (Personenrecht, Familienrecht, Erbrecht, Sachenrecht) sowie das OR (als 5. Teil des ZGB). Alle diese regeln Rechtsbeziehungen zwischen gleichberechtigten Privaten. Das Strafrecht gehört dagegen zum öffentlichen Recht — der Staat tritt hier mit hoheitlicher Gewalt auf.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Personenrecht ist Teil des ZGB (Privatrecht).' }, { feld: 'optionen', id: 'opt-1', text: 'Strafrecht ist öffentliches Recht — nicht Privatrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Familienrecht ist Teil des ZGB (Privatrecht).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Sachenrecht (Art. 641 ff. ZGB) ist Privatrecht.' } ] },
  { id: 'e2a59985-d1d0-49c8-b81f-759a8af51870', fachbereich: 'Recht', musterlosung: 'Nach OR 21 liegt Übervorteilung vor bei: (1) offensichtlichem Missverhältnis zwischen Leistung und Gegenleistung (hier 60\'000 vs. 15\'000) und (2) Ausnutzung der Notlage, des Leichtsinns oder der Unerfahrenheit einer Partei. Beide Voraussetzungen sind erfüllt. Es liegt weder Täuschung noch Drohung vor. Die benachteiligte Partei kann den Vertrag innert Jahresfrist anfechten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine aktive Täuschung (OR 28) — Schwäche wurde ausgenutzt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Übervorteilung (OR 21) — Missverhältnis + Ausnutzung.' }, { feld: 'optionen', id: 'opt-2', text: 'Grundlagenirrtum (OR 24 Abs. 1 Ziff. 4) erfordert gemeinsame Fehlvorstellung.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Drohung (OR 29) — keine Androhung eines Übels.' } ] },
  { id: 'e33b81e4-ac0c-4ad3-ba47-e0dea16690d8', fachbereich: 'Recht', musterlosung: 'Die «actio libera in causa» (Art. 19 Abs. 4 StGB): Hat der Täter die temporäre Schuldunfähigkeit selbst verursacht (z.B. durch freiwilligen Alkoholkonsum), kann er sich nicht auf Schuldunfähigkeit berufen. Marco hat sich absichtlich stark betrunken und dann gefahren — er ist zu bestrafen. Auch Alkohol fällt unter Art. 19 StGB, nicht nur psychische Störungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Selbst verschuldete Schuldunfähigkeit hebt Strafbarkeit nicht auf (actio libera in causa).' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 19 StGB umfasst auch Rausch — nicht nur psychische Störungen.' }, { feld: 'optionen', id: 'opt-2', text: 'Trunkenheit ist nicht per se Schuldausschliessungsgrund — siehe Art. 19 Abs. 4.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Actio libera in causa (Art. 19 Abs. 4 StGB) — selbstverschuldete Schuldunfähigkeit.' } ] },
  { id: 'e3a0ceef-6ed7-4e4c-8739-77bd0ddabcde', fachbereich: 'Recht', musterlosung: 'CHF 301.– × 365 Tage = CHF 109\'865.– — also rund CHF 110\'000.– pro Jahr im Normalvollzug. Diese hohen Kosten sind ein Grund, warum das StGB Alternativen vorsieht (bedingter Strafvollzug, elektronische Überwachung, gemeinnützige Arbeit). Freiheitsstrafen belasten die Gesellschaft direkt wie indirekt (Resozialisierungshürden, Familien).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'CHF 55\'000 wäre etwa die Hälfte — zu tief.' }, { feld: 'optionen', id: 'opt-1', text: 'CHF 80\'000 ist zu tief — 301×365 liegt höher.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: CHF 301 × 365 ≈ CHF 110\'000.' }, { feld: 'optionen', id: 'opt-3', text: 'CHF 150\'000 wäre zu hoch — 301×365 liegt darunter.' } ] },
  { id: 'e64f78bf-cde5-4f87-989c-9d86fc34af37', fachbereich: 'Recht', musterlosung: 'Bei der Miete wird dem Mieter nur der Gebrauch einer Sache überlassen (Art. 253 OR). Bei der Pacht darf der Pächter die Sache nutzen UND deren Früchte und Erträge ziehen (Art. 275 OR) — z.B. die Ernte eines Ackers, den Umsatz eines Restaurants. Die Pacht ist umfangreicher als die Miete; sie setzt eine ertragsbringende Sache voraus.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beide können befristet oder unbefristet sein — kein Unterscheidungsmerkmal.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Pacht = Nutzung + Ertragsziehung (Art. 275 OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Eigentumsübertragung — nur Nutzungsrecht bei beiden.' }, { feld: 'optionen', id: 'opt-3', text: 'Klare Unterscheidung — Früchteziehung macht den Kern aus.' } ] },
  { id: 'e6b43e35-4237-4850-b8c4-82628995cb5a', fachbereich: 'Recht', musterlosung: 'Verhältnismässigkeit nach Art. 36 Abs. 3 BV hat zwei Komponenten: (1) Eignung — die Massnahme muss geeignet sein, das angestrebte Ziel zu erreichen; (2) Verhältnismässigkeit im engeren Sinne (Zumutbarkeit) — der Eingriff muss für den Betroffenen im angemessenen Verhältnis zum verfolgten Zweck stehen. Üblicherweise wird zudem geprüft, ob mildere Mittel verfügbar sind.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Eignung + Zumutbarkeit als zwei Komponenten.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine starre Zeitgrenze — Verhältnismässigkeit ist qualitativ.' }, { feld: 'optionen', id: 'opt-2', text: 'Mehrheitsunterstützung ist politisches, nicht verfassungsrechtliches Kriterium.' }, { feld: 'optionen', id: 'opt-3', text: 'Gerichtliche Anordnung ist nicht zwingend — Behörden können verhältnismässig handeln.' } ] },
  { id: 'e754338c-e904-47b4-93fb-c73b59e3abcb', fachbereich: 'Recht', musterlosung: 'Im Strafregister (VOSTRA, Art. 365 ff. StGB) werden rechtskräftige Verurteilungen eingetragen: Freiheitsstrafen, Geldstrafen und bestimmte Massnahmen. Blosse Strafanzeigen werden nicht eingetragen. Die Einträge werden nach einer gesetzlich festgelegten Frist (abhängig von Strafhöhe) von Amtes wegen gelöscht. Bussen erscheinen in der Regel nicht im Strafregister.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Strafen ab einem Jahr — auch kürzere Strafen werden eingetragen.' }, { feld: 'optionen', id: 'opt-1', text: 'Anzeigen ohne Verurteilung werden nicht eingetragen — nur rechtskräftige Urteile.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Rechtskräftige Verurteilungen — werden nach Frist gelöscht.' }, { feld: 'optionen', id: 'opt-3', text: 'Einträge werden nach Fristablauf gelöscht — nicht ewig gespeichert.' } ] },
  { id: 'e7f42ce8-47ba-4a79-a51a-cd02de4eeb8e', fachbereich: 'Recht', musterlosung: 'Der Straftatbestand im besonderen Teil des StGB definiert den Strafrahmen — also die höchstmögliche Strafe für die schlimmstmögliche Variante dieses Delikts. Das Gericht bemisst die Strafe innerhalb dieses Rahmens unter Berücksichtigung der individuellen Umstände (Art. 47 StGB). Eine Mindeststrafe ist häufig, aber nicht immer vorgesehen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Strafhöhe ist mitgeregelt — nicht nur die Art.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Strafrahmen = Höchstmass; Gericht bemisst innerhalb dessen.' }, { feld: 'optionen', id: 'opt-2', text: 'Mindeststrafe ist nicht immer vorgesehen — Ermessensspielraum nach unten.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein exaktes Strafmass — Gericht hat Bemessungsspielraum.' } ] },
  { id: 'e85bafc0-eba2-40f3-8bed-52e2a9ca99be', fachbereich: 'Recht', musterlosung: 'Eine defekte Heizung ist ein Mangel an der Mietsache während des laufenden Mietverhältnisses. Die relevanten Bestimmungen fallen unter den Bereich «Während der Miete» (Art. 259 ff. OR — Mängelrechte). Leona muss nicht kündigen, sondern kann Mängelbeseitigung verlangen, Mietzinsreduktion fordern oder den Mietzins hinterlegen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Während der Miete (Art. 259 ff. OR) — Mängelrechte.' }, { feld: 'optionen', id: 'opt-1', text: 'Mieterschutz-Bestimmungen (Art. 270 ff.) betreffen Mietzinsanfechtung.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Kündigung nötig — Leona kann Mängelbeseitigung verlangen.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Vertragsabschluss-Frage — hier geht es um laufende Pflichten.' } ] },
  { id: 'e863564b-d891-4819-9627-2fbbb573c090', fachbereich: 'Recht', musterlosung: 'GAV regeln kollektiv die Arbeitsbedingungen für Branchen oder Regionen. Grundsätzlich binden sie nur Verbandsmitglieder — durch Allgemeinverbindlichkeitserklärung (AVE) durch den Bundesrat können sie aber für alle Betriebe der Branche gelten. Abweichungen vom GAV zugunsten des Arbeitnehmers sind zulässig — der GAV setzt Mindeststandards.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: GAVs regeln ganze Branchen/Regionen kollektiv.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — durch AVE gelten GAVs auch für Nicht-Mitglieder.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Allgemeinverbindlichkeitserklärung macht GAV für alle bindend.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Abweichungen zugunsten des AN bleiben möglich.' } ] },
  { id: 'e8636b35-9b53-4727-b1c1-f6aef351c7cd', fachbereich: 'Recht', musterlosung: 'Die vier Voraussetzungen von Art. 36 BV gelten kumulativ: gesetzliche Grundlage, öffentliches Interesse (oder Schutz von Grundrechten Dritter), Verhältnismässigkeit und unantastbarer Kerngehalt müssen alle gleichzeitig erfüllt sein. Fehlt auch nur eine Voraussetzung, ist die Grundrechtseinschränkung unzulässig. Das Kumulativprinzip schützt die Grundrechte effektiv.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Alle vier Voraussetzungen müssen kumulativ erfüllt sein.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Alternativität — eine Voraussetzung allein genügt nicht.' }, { feld: 'optionen', id: 'opt-2', text: 'Auch verwaltungsrechtlich sind die Voraussetzungen zu beachten — nicht nur vor Gericht.' }, { feld: 'optionen', id: 'opt-3', text: 'Auch bei leichten Eingriffen sind alle Voraussetzungen zu prüfen.' } ] },
  { id: 'e8f11931-96f6-4e3d-94b8-8ce96c339728', fachbereich: 'Recht', musterlosung: 'Beim Miteigentum (Art. 646 ff. ZGB) hat jeder Miteigentümer einen ideellen Bruchteil (Wertquote) und kann darüber grundsätzlich frei verfügen (z.B. Anteil verkaufen, verpfänden). Beim Gesamteigentum (Art. 652 ff. ZGB) gibt es keine individuellen Anteile — alle Gesamteigentümer sind gemeinsam berechtigt und können nur einstimmig verfügen (Art. 653 Abs. 2 ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beide Formen gelten für jede Sachart — kein Unterschied nach Sachtyp.' }, { feld: 'optionen', id: 'opt-1', text: 'Beide sind gemeinschaftliches Eigentum mehrerer — Unterschied liegt in der Struktur.' }, { feld: 'optionen', id: 'opt-2', text: 'Beide können durch Vertrag oder Erbgang entstehen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Miteigentum = ideelle Bruchteile, Gesamteigentum = gemeinsame Verfügung.' } ] },
  { id: 'e9ce26b9-4cb7-4c32-88a3-06e1a0c2a595', fachbereich: 'Recht', musterlosung: 'Die BV verankert zahlreiche Grundrechte (Art. 7–36): Versammlungsfreiheit (Art. 22), Glaubens- und Gewissensfreiheit (Art. 15), persönliche Freiheit (Art. 10), Meinungsfreiheit (Art. 16) und andere. Das «Recht auf eine Wohnung» ist kein eigenständiges Grundrecht — es ist ein Sozialziel (Art. 41 Abs. 1 Bst. e BV), aus dem Einzelne keine direkten Leistungsansprüche ableiten können.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Versammlungsfreiheit (Art. 22 BV) — eigenständiges Grundrecht.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — Wohnraum ist Sozialziel (Art. 41 BV), kein einklagbares Grundrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Glaubens- und Gewissensfreiheit (Art. 15 BV).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Persönliche Freiheit (Art. 10 BV).' } ] },
  { id: 'e9ecf47a-2a19-4885-8f72-14c1fb0e6fe2', fachbereich: 'Recht', musterlosung: 'Das Grundbuch ist ein staatliches Register nach Art. 942 ZGB, das über die dinglichen Rechte an Grundstücken Auskunft gibt. Es ist öffentlich (Art. 970 ZGB), sodass jeder mit berechtigtem Interesse Einsicht nehmen kann. Eingetragen werden Eigentum, Dienstbarkeiten, Grundlasten und Pfandrechte (Art. 958 ZGB). Heute ist das Grundbuch grossteils elektronisch.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Staatliches Register für dingliche Rechte an Grundstücken (Art. 942 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre das Handelsregister — andere Funktion.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Privatverzeichnis — staatlich geführt.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht nur Geometrie — auch Rechte werden erfasst (Katasterplan ist separat).' } ] },
  { id: 'ebeb16c4-08ea-44e2-a788-089b440268f2', fachbereich: 'Recht', musterlosung: 'In der Schweiz darf das Bundesgericht Bundesgesetze nicht auf ihre Verfassungsmässigkeit überprüfen (Art. 190 BV). Praktisch geht Verfassung deshalb nicht automatisch Gesetzen vor — die Norm «lex superior derogat inferiori» gilt auf Bundesebene nur eingeschränkt. Bei Verordnungen prüft das Bundesgericht indirekt die Verfassungsmässigkeit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Schweiz hat ein Bundesgericht — nur nicht mit Verfassungsgerichtsbarkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — nicht jedes Gesetz ist automatisch verfassungskonform.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Art. 190 BV verhindert die Verfassungsprüfung von Bundesgesetzen.' }, { feld: 'optionen', id: 'opt-3', text: 'Kantonale Gerichte haben diese Aufgabe nicht — sie sind an Bundesgesetze gebunden.' } ] },
  { id: 'ec1f4603-63e4-4e17-860b-c78509c5154d', fachbereich: 'Recht', musterlosung: 'Im Zivilprozess richtet sich die sachliche Zuständigkeit u.a. nach dem Streitwert. Die örtliche Zuständigkeit bestimmt den Gerichtsort — grundsätzlich am Wohnsitz des Beklagten (Art. 10 ZPO), bei Grundstücken aber am Ort des Grundstücks (forum rei sitae). Der Kläger kann den Gerichtsort nicht frei wählen — es gelten gesetzliche Regeln.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Sachliche Zuständigkeit oft nach Streitwert.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Örtliche Zuständigkeit = Gerichtsort.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine freie Wahl — gesetzliche Regeln gelten.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Bei Grundstücken forum rei sitae (Ort des Grundstücks).' } ] },
  { id: 'ec82ffa5-daee-41d6-b94c-ec0ef5415201', fachbereich: 'Recht', musterlosung: 'Art. 323 Abs. 1 ZGB (in der alten Nummerierung; heute unter dem ehelichen Güterrecht) räumt Unmündigen das Recht ein, über den Ertrag ihrer Arbeit (Lohn aus Ferienjob, Lehrlingslohn) frei zu verfügen. Dies ist eine Ausnahme zur Zustimmungspflicht nach Art. 19 Abs. 1 ZGB. Der Unmündige kann mit seinem selbst verdienten Geld eigenständig Käufe tätigen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Sparpflicht — Unmündige dürfen über Arbeitslohn verfügen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Selbstständige Verfügung über eigenen Arbeitslohn (Art. 323 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Das ist eine besondere Ausnahme zugunsten der Unmündigen.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht unbegrenzt — nur eigener Arbeitslohn, nicht geschenktes Geld.' } ] },
  { id: 'eda85ad2-7bb1-44c4-b484-066c8d1e5077', fachbereich: 'Recht', musterlosung: 'Nach Art. 42 Abs. 1 StGB können Freiheitsstrafen von weniger als 2 Jahren (bis 24 Monate) sowie Geldstrafen und gemeinnützige Arbeit bedingt ausgesprochen werden, wenn eine unbedingte Strafe nicht notwendig erscheint, um den Täter von weiteren Straftaten abzuhalten. Der bedingte Vollzug koppelt die Strafe an ein Wohlverhalten in einer Probezeit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht alle Strafen — es gibt Höchstgrenzen (< 2 Jahre).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Freiheitsstrafen < 2 Jahre, Geldstrafen, gemeinnützige Arbeit (Art. 42 StGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Unvollständig — auch Freiheitsstrafen < 2 Jahre sind erfasst.' }, { feld: 'optionen', id: 'opt-3', text: '< 5 Jahre wäre zu weit — Teilbedingter Vollzug gilt bis 36 Monate (Art. 43 StGB).' } ] },
  { id: 'ee06183a-db81-4d81-beed-8f9cf97967a9', fachbereich: 'Recht', musterlosung: 'Legalitätsprinzip und Grundrechte sind sich ergänzende Begrenzungen der Staatsmacht. Das Legalitätsprinzip (Art. 5 Abs. 1 BV) verlangt eine gesetzliche Grundlage für jedes staatliche Handeln. Die Grundrechte setzen darüber hinaus inhaltliche Grenzen — auch wenn ein Gesetz existiert, darf es die Grundrechte nur unter den Voraussetzungen von Art. 36 BV einschränken.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Grundrechte gelten immer — nicht nur bei Einhaltung des Legalitätsprinzips.' }, { feld: 'optionen', id: 'opt-1', text: 'Beide richten sich an den Staat — enger Zusammenhang.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gemeinsame Begrenzung der Staatsmacht — formell + inhaltlich.' }, { feld: 'optionen', id: 'opt-3', text: 'Das Legalitätsprinzip ist ein rechtsstaatlicher Grundsatz — kein Grundrecht.' } ] },
  { id: 'ee0a5b39-f95e-4bef-a635-dab126213015', fachbereich: 'Recht', musterlosung: 'Die elektronische Überwachung (Art. 79 Abs. 1 StGB) ist bei Freiheitsstrafen von 20 Tagen bis 12 Monaten möglich. Die verurteilte Person lebt ausserhalb der Anstalt, wird aber elektronisch überwacht (z.B. Fussfessel). Die Massnahme kann auch für die letzten 3 bis 12 Monate einer langen Haftstrafe angeordnet werden (Art. 79b StGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Lebenslange Strafen sind ausgeschlossen — elektronische Überwachung ist Alternative zu kurzen Strafen.' }, { feld: 'optionen', id: 'opt-1', text: '1–5 Jahre sind zu lange — Obergrenze ist 12 Monate.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 20 Tage bis 12 Monate (Art. 79 Abs. 1 StGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht alle Freiheitsstrafen — nur kurze.' } ] },
  { id: 'ee699e67-9009-4804-a164-a98a0ecffe82', fachbereich: 'Recht', musterlosung: 'Nach OR 321d muss der Arbeitnehmer die Weisungen des Arbeitgebers grundsätzlich befolgen. Dies gilt aber nicht für sittenwidrige oder gesetzwidrige Weisungen (z.B. Täuschung eines Kunden). Der Schutz der Persönlichkeit und der öffentlichen Ordnung geht vor. Der Arbeitnehmer darf und sollte solche Weisungen ablehnen, ohne dass eine Kündigung droht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht alle Weisungen — gesetzwidrige und sittenwidrige sind ausgenommen.' }, { feld: 'optionen', id: 'opt-1', text: 'Weisungen sind nicht absolut bindend — Grenze bei Rechtswidrigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Schriftlicher Protest ist nicht Voraussetzung — die Ablehnung ist immer zulässig.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Sittenwidrige/gesetzwidrige Weisungen müssen nicht befolgt werden.' } ] },
  { id: 'eeffb2aa-a536-402e-8f1d-8838ba3608b7', fachbereich: 'Recht', musterlosung: 'Die vertragliche Haftung (OR 97) setzt einen gültigen Vertrag voraus. Die ausservertragliche Haftung (OR 41 ff.) greift ohne Vertrag — z.B. bei Verkehrsunfällen. Beide Haftungsarten können parallel bestehen (Anspruchskonkurrenz, z.B. Anwaltshaftung). Bei OR 97 gilt Beweislastumkehr — der Schuldner muss beweisen, dass ihn kein Verschulden trifft.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Vertragliche Haftung setzt Vertrag voraus (OR 97).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: OR 41 ff. greift ohne Vertrag (Delikt).' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — Anspruchskonkurrenz ist möglich (parallele Anwendung).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Beweislastumkehr bei OR 97 — Schuldner muss Entlastung beweisen.' } ] },
  { id: 'ef3995c8-bc1a-4475-8d3b-222e6f5392ad', fachbereich: 'Recht', musterlosung: 'Nach OR 493 bedarf die Bürgschaft der schriftlichen Form, und der Höchstbetrag der Haftung muss ausdrücklich festgehalten werden. Der Bürge haftet nur bis zu diesem Höchstbetrag (OR 499). Bei natürlichen Personen und Beträgen über CHF 2\'000 ist zudem öffentliche Beurkundung erforderlich (qualifizierte Form).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Mündlich genügt nicht — Schutzfunktion der Schriftform.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Schriftform + Höchstbetrag zwingend (OR 493).' }, { feld: 'optionen', id: 'opt-2', text: 'Öffentliche Beurkundung nur bei höheren Beträgen natürlicher Personen.' }, { feld: 'optionen', id: 'opt-3', text: 'Formvorschrift besteht — zwingendes Schutzrecht.' } ] },
  { id: 'einr-ag-material-mc', fachbereich: 'Recht', musterlosung: 'Die Aufgabe prüft, ob die Prüflinge das Materialpanel in ExamLab korrekt bedienen und im bereitgestellten PDF «Amtliche Witzsammlung» nachschlagen können. Art. 5 im Kapitel 2 (Seite 3) trägt den Titel «Die Schulglocke». Die Frage ist ein Einrichtungstest, der das Zurechtfinden im Materialpanel einübt.', teilerklaerungen: [ { feld: 'optionen', id: 'a', text: 'Der Taschenrechner ist nicht Titel von Art. 5 in der Witzsammlung.' }, { feld: 'optionen', id: 'b', text: 'Korrekt: «Die Schulglocke» steht als Titel bei Art. 5 auf Seite 3.' }, { feld: 'optionen', id: 'c', text: 'Das Klassenzimmer ist nicht Titel von Art. 5.' }, { feld: 'optionen', id: 'd', text: 'Der Sportlehrer ist nicht Titel von Art. 5.' } ] },
  { id: 'f097814e-59be-49b0-b0e0-f962aba99a41', fachbereich: 'Recht', musterlosung: 'Art. 29 Abs. 2 AEMR lässt Beschränkungen von Menschenrechten zu — aber nur unter strengen Bedingungen: (1) gesetzlich vorgesehen, (2) zur Sicherung der Rechte anderer und (3) zur Erfüllung der Anforderungen der Moral, der öffentlichen Ordnung und des allgemeinen Wohls in einer demokratischen Gesellschaft. Die Parallelen zu Art. 36 BV sind deutlich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Mehrheitsmeinung allein rechtfertigt keine Rechtseinschränkung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Gesetz + Rechte anderer/öffentliches Wohl + demokratische Gesellschaft.' }, { feld: 'optionen', id: 'opt-2', text: 'Auch Krisenzeiten kennen Grenzen — insbesondere Kerngehaltsschutz.' }, { feld: 'optionen', id: 'opt-3', text: 'Menschenrechte gelten nicht absolut in jeder Dimension — Einschränkungen sind vorgesehen.' } ] },
  { id: 'f0c94568-8545-4a1c-8883-60e55bfb6b7d', fachbereich: 'Recht', musterlosung: 'Beim Werkvertrag (OR 363–379) schuldet der Unternehmer ein bestimmtes Arbeitsresultat (das Werk). Beim Arbeitsvertrag (OR 319–362) schuldet der Arbeitnehmer nur sorgfältige Arbeit — kein bestimmtes Resultat. Der Arbeitnehmer ist untergeordnet und weisungsgebunden; der Unternehmer handelt selbstständig. Beim Auftrag (OR 394 ff.) ist ebenfalls nur sorgfältige Tätigkeit geschuldet, aber ohne Unterordnung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein Formerfordernis — beide Verträge sind formfrei (Ausnahme Lehrvertrag).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Werk = Resultat, Arbeit = sorgfältige Tätigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Unterschiedliche Verträge mit unterschiedlichen Regeln.' }, { feld: 'optionen', id: 'opt-3', text: 'Werkvertrag gilt für alle Werke — nicht nur Bau.' } ] },
  { id: 'f4412549-528e-40ea-bee5-819262ff71d0', fachbereich: 'Recht', musterlosung: 'Zentrale Rechtsgrundsätze: «Wo kein Kläger, da kein Richter» gilt im Zivilprozess (Verhandlungsmaxime). Art. 49 BV: Bundesrecht bricht kantonales Recht. «Ignorantia iuris nocet»: Rechtsunkenntnis schützt nicht. Aber: In der Schweiz gibt es keine Verfassungsgerichtsbarkeit für Bundesgesetze (Art. 190 BV).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Verhandlungsmaxime im Zivilprozess.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Art. 49 BV — Bundesrecht bricht kantonales Recht.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: «Ignorantia iuris nocet» — Rechtsunkenntnis schadet.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — BG darf Bundesgesetze nicht auf Verfassungsmässigkeit prüfen (Art. 190 BV).' } ] },
  { id: 'f443b213-328c-4549-9099-277da2675e49', fachbereich: 'Recht', musterlosung: 'Art. 16 ZGB nennt als Gründe für fehlende Urteilsfähigkeit: Kindesalter, geistige Behinderung, psychische Störung, Rausch oder ähnliche Zustände. Ein 3-jähriges Kind, eine geistig behinderte Person oder eine stark betrunkene Person können urteilsunfähig sein. Die blosse Minderjährigkeit (z.B. mit 17 Jahren) führt dagegen nicht zur Urteilsunfähigkeit — ein 17-Jähriger ist urteilsfähig, aber nicht mündig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Kleinkinder sind typisch urteilsunfähig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Geistige Behinderung kann Urteilsunfähigkeit begründen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Starker Rausch kann zur vorübergehenden Urteilsunfähigkeit führen.' }, { feld: 'optionen', id: 'opt-3', text: 'Minderjährigkeit allein ist kein Urteilsunfähigkeitsgrund — ein 17-Jähriger ist urteilsfähig.' } ] },
  { id: 'f50077a8-5b88-41b9-8c15-82a523df1f95', fachbereich: 'Recht', musterlosung: 'Eine fristlose Kündigung (OR 337) erfordert einen wichtigen Grund — ein Verhalten, das die Fortsetzung des Arbeitsverhältnisses für die andere Partei unzumutbar macht. Mangelnde Kompetenz oder sachliche Fehler sind normalerweise keine wichtigen Gründe — dafür gibt es die ordentliche Kündigung mit Frist. Nur schwere Verstösse oder Treuebrüche rechtfertigen fristlose Entlassung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht jederzeit — ordentliche Kündigung braucht Fristen.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur persönliches Fehlverhalten — auch Treuebruch, grober Verstoss.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Mangelnde Kompetenz ist kein wichtiger Grund — ordentliche Kündigung reicht.' }, { feld: 'optionen', id: 'opt-3', text: 'Schwere kann nicht alle Verhaltensweisen umfassen — Art der Fehler ist entscheidend.' } ] },
  { id: 'f5388b66-b274-4833-9486-69f97417fdf4', fachbereich: 'Recht', musterlosung: 'Die Werkeigentümerhaftung nach OR 58 ist eine einfache Kausalhaftung: Der Werkeigentümer haftet für Schäden, die durch fehlerhafte Anlage oder mangelhaften Unterhalt seines Werks entstehen — unabhängig vom Verschulden. Ein Dach ohne Schneefänger, das zu einem Dachlawinenschaden führt, ist ein mangelhaft unterhaltenes Werk.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Verschuldenshaftung setzt Sorgfaltspflichtverletzung voraus — OR 58 ist verschuldensunabhängig.' }, { feld: 'optionen', id: 'opt-1', text: 'Tierhalterhaftung (OR 56) betrifft Tiere — hier ist das Werk die Ursache.' }, { feld: 'optionen', id: 'opt-2', text: 'Gefährdungshaftung betrifft besonders gefährliche Anlagen (Motorfahrzeuge) — hier reicht OR 58.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Werkeigentümerhaftung nach OR 58 — mangelhafter Unterhalt.' } ] },
  { id: 'f5401309-87d0-4ad3-9f7d-f22979039ba8', fachbereich: 'Recht', musterlosung: 'Das Bundesgericht argumentierte für die Verfassungskonformität von Art. 29b PolG BE: (1) Offen formuliert, aber ausreichend als gesetzliche Grundlage; (2) Öffentliches Interesse liegt im Unterbinden «negativer Erscheinungen» im Umfeld von Drogen-/Alkoholszenen; (3) Zeitlich und räumlich begrenzte Wegweisungen sind geeignet und verhältnismässig. Die Menschenwürde ist gewahrt — die Wegweisung folgt dem Verhalten, nicht der Person.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Art. 29b PolG BE als ausreichend offene, aber gültige Grundlage.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Öffentliches Interesse — negative Erscheinungen im öffentlichen Raum.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verhältnismässigkeit durch sachliche und örtliche Begrenzung.' }, { feld: 'optionen', id: 'opt-3', text: 'Das BG sah die Menschenwürde gewahrt — Verhalten, nicht Person wird sanktioniert.' } ] },
  { id: 'f546e6bd-59fa-4643-a7a0-4aee88aa5809', fachbereich: 'Recht', musterlosung: 'Fehlt eine der drei Vertragsvoraussetzungen (Willenserklärung nach OR 1, gültiger Inhalt nach OR 19/20, korrekte Form nach OR 11 ff.), ist der Vertrag nichtig — er entfaltet von Anfang an keine Wirkung. Dies unterscheidet sich von der Anfechtbarkeit bei Willensmängeln (OR 23 ff.), wo der Vertrag bis zur Anfechtung gültig bleibt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Anfechtbarkeit gilt bei Willensmängeln — nicht bei fehlenden Voraussetzungen.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine richterliche Anpassung — Vertrag ist ex lege unwirksam.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Vertrag nichtig — keine Wirkung von Anfang an.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein Schadenersatz aus nichtigem Vertrag — allenfalls culpa in contrahendo.' } ] },
  { id: 'f56c5c9d-af1b-4de6-8bb0-c47015d2677f', fachbereich: 'Recht', musterlosung: 'Das Mietrecht enthält zahlreiche zwingende Vorschriften zum Schutz des Mieters als schwächerer Partei. Abweichungen sind nur zugunsten des Mieters zulässig — nicht zu seinen Ungunsten. Der Mietvertrag ist grundsätzlich formfrei (OR 11) — eine Schriftpflicht besteht nicht. Koppelungsgeschäfte (z.B. Mietvertrag verlangt zusätzlichen Kauf) sind nach Art. 254 OR verboten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Zwingende Schutzvorschriften für den Mieter.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Abweichung zugunsten des Mieters zulässig (relative Zwingendheit).' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — Mietvertrag ist formfrei.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Koppelungsgeschäfte verboten (Art. 254 OR).' } ] },
  { id: 'f68b5ab4-f3a1-4a47-a8b8-61e5f0c699fb', fachbereich: 'Recht', musterlosung: 'Die paritätische Lebensdauertabelle wird vom Hauseigentümerverband (HEV) und dem Schweizerischen Mieterinnen- und Mieterverband (SMV) gemeinsam herausgegeben. Sie legt fest, wie lange verschiedene Einrichtungsgegenstände (Wandanstrich, Parkett, Kühlschrank, Waschmaschine) üblicherweise halten. Sie dient der Berechnung des Zeitwerts bei Schadenersatzforderungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Lebenserwartung von Menschen — es geht um Einrichtungsgegenstände.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Pflichtenliste — Zeitwerte von Einrichtungsgegenständen.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Mietpreisübersicht — Lebensdauer ist anderes Thema.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Zeitwerte von Einrichtungsgegenständen (paritätisch HEV/SMV).' } ] },
  { id: 'f7adeede-7bc9-4ccc-aab2-767010583de8', fachbereich: 'Recht', musterlosung: 'Die Hauptpflichten des Arbeitnehmers nach OR 321 ff.: Persönliche Arbeitspflicht (OR 321 — nicht delegierbar ohne Zustimmung), Sorgfalts- und Treuepflicht (OR 321a), Befolgung von Weisungen (OR 321d — aber nicht bei Gesetzwidrigkeit), Haftung für fahrlässig verursachte Schäden (OR 321e). Unbequeme Weisungen sind gleichwohl zu befolgen — nur gesetz-/sittenwidrige nicht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Persönliche Arbeitspflicht — höchstpersönliche Leistung (OR 321).' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — nur gesetz-/sittenwidrige Weisungen dürfen ignoriert werden.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Sorgfalts- und Treuepflicht (OR 321a).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Haftung für fahrlässige Schäden (OR 321e).' } ] },
  { id: 'f88d3c79-272e-4442-87b7-a9bacf0b70b2', fachbereich: 'Recht', musterlosung: 'Ein Schiedsgericht ist eine private Gerichtsbarkeit: Die Parteien vereinbaren, ihren Streit nicht vor einem staatlichen Gericht, sondern vor einem oder mehreren privaten Schiedsrichtern auszutragen. Das Schiedsurteil ist bindend und wie ein Gerichtsurteil vollstreckbar. Schiedsgerichte werden oft in internationalen Handelsverträgen vereinbart, um Neutralität und Schnelligkeit zu sichern.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Streitwertgrenze — Schiedsgerichte gerade bei hohen Streitwerten üblich.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein staatliches Gericht — private Gerichtsbarkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Privates Gericht mit bindendem Urteil.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht kostenlos — Parteien zahlen die Schiedsrichter selbst.' } ] },
  { id: 'f95d0eda-8696-4a70-82c8-dafafe2b12e7', fachbereich: 'Recht', musterlosung: 'Einfache Kausalhaftungen (verschuldensunabhängig): Geschäftsherr (OR 55 — Haftung für Hilfspersonen), Tierhalter (OR 56), Familienoberhaupt (ZGB 333), Werkeigentümer (OR 58). Die Motorfahrzeughaftung nach SVG 58 ist dagegen eine Gefährdungshaftung (scharfe Kausalhaftung) — strenger wegen des besonderen Gefahrenpotenzials von Motorfahrzeugen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Geschäftsherr (OR 55) — einfache Kausalhaftung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Tierhalter (OR 56) — einfache Kausalhaftung.' }, { feld: 'optionen', id: 'opt-2', text: 'Motorfahrzeughalter ist Gefährdungshaftung — nicht einfache Kausalhaftung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Werkeigentümer (OR 58) — einfache Kausalhaftung.' } ] },
  { id: 'fa0c2c53-98dd-4ad8-9fcf-c1f0cea5f222', fachbereich: 'Recht', musterlosung: 'A durfte auf die Richtigkeit der gerichtlichen Rechtsmittelbelehrung vertrauen. Dieses berechtigte Vertrauen wird durch Art. 2 Abs. 1 ZGB (Treu und Glauben) geschützt. Die obere Instanz muss deshalb trotz eigentlich verspäteter Eingabe auf die Beschwerde eintreten — der Fehler des unteren Gerichts darf A nicht zum Nachteil gereichen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Abweisung würde A für den Fehler des Gerichts bestrafen — widerspricht Treu und Glauben.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 3 ZGB betrifft den guten Glauben über Tatsachen — hier geht es um Vertrauen in behördliche Auskunft.' }, { feld: 'optionen', id: 'opt-2', text: 'Das Vertrauen in die Belehrung schützt A — Rechtsunkenntnis spielt hier keine Rolle.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Treu und Glauben schützen Vertrauen in Rechtsmittelbelehrung (Art. 2 Abs. 1 ZGB).' } ] },
  { id: 'fa0cf1be-d53f-43ab-8655-fbad32237a72', fachbereich: 'Recht', musterlosung: 'Die Handlung des Polizisten ist durch die gesetzlich erlaubte Handlung (Art. 14 StGB) gedeckt. Die Polizei darf nach dem Polizeigesetz bestimmte Handlungen durchführen, die sonst strafbar wären (z.B. Freiheitsbeschränkung, angemessene Gewalt bei Verhaftung). Keine Notwehr (Art. 15), weil kein rechtswidriger Angriff des Verdächtigen vorliegt. Der Polizist ist straffrei, sofern er die gesetzlichen Grenzen einhält.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Einwilligung ist nicht der Rechtfertigungsgrund — Amtshandlung zählt.' }, { feld: 'optionen', id: 'opt-1', text: 'Gewalt im Rahmen des Polizeigesetzes ist erlaubt — nicht jede Gewalt ist strafbar.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Notwehr — es fehlt ein rechtswidriger Angriff gegen den Polizisten.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gesetzlich erlaubte Handlung (Art. 14 StGB) — Polizeigesetz als Grundlage.' } ] },
  { id: 'fb6ccd6b-99bd-4ec4-8d8c-cbe54419d3ee', fachbereich: 'Recht', musterlosung: 'Der Bundesrat kann die Allgemeinverbindlichkeit eines GAV erklären (Art. 1 AVEG, OR 356 Abs. 3). Diese Erklärung macht die GAV-Bestimmungen auch für nicht-organisierte Arbeitnehmer und Arbeitgeber derselben Branche bindend. Voraussetzung: Repräsentativität der vertragschliessenden Verbände und öffentliches Interesse an der Ausdehnung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Bundesrat erklärt die AVE (Art. 356 Abs. 3 OR, AVEG).' }, { feld: 'optionen', id: 'opt-1', text: 'Gerichte wenden GAV an, erklären sie aber nicht allgemeinverbindlich.' }, { feld: 'optionen', id: 'opt-2', text: 'Verbände schliessen den GAV — aber AVE ist Bundesratsakt.' }, { feld: 'optionen', id: 'opt-3', text: 'Kantonrat hat keine Kompetenz — Bundessache.' } ] },
  { id: 'fc93423b-2b6d-43b9-9e5b-00c527957b3f', fachbereich: 'Recht', musterlosung: 'Der Grundsatz der ungerechtfertigten Bereicherung nach OR 62: Wer ohne gültigen Rechtsgrund bereichert worden ist, muss die Bereicherung zurückerstatten. Das Prinzip lautet: Keine Bereicherung ohne Rechtsgrund. Es sichert die Zuordnung von Vermögenswerten nach den rechtsgeschäftlichen oder gesetzlichen Grundlagen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Schriftform ist kein allgemeines Erfordernis — OR 62 ist anderes Thema.' }, { feld: 'optionen', id: 'opt-1', text: 'Bereicherung ist nicht per se strafbar — nur ohne Rechtsgrund rückerstattungspflichtig.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Rückerstattung bei Vermögensverschiebung ohne Rechtsgrund.' }, { feld: 'optionen', id: 'opt-3', text: 'Steuerfragen sind anderes Gebiet — nicht OR 62.' } ] },
  { id: 'fcd925d5-076f-4db6-a324-d8f18199a4ab', fachbereich: 'Recht', musterlosung: 'Die COVID-19-Massnahmen waren aus zwei Hauptgründen kontrovers: (1) Demokratische Legitimation — sie wurden per Notverordnung des Bundesrats (Art. 185 Abs. 3 BV) ohne Parlamentsbeteiligung erlassen; erst das COVID-19-Gesetz schuf eine ordentliche Grundlage. (2) Verhältnismässigkeit — die weitreichenden Einschränkungen (Lockdown, Versammlungsverbote, Schliessungen) waren umstritten. Die Volksabstimmung 2021 zeigte die gesellschaftliche Spaltung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das BG hat die Massnahmen nicht sofort verworfen — eher bestätigt.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Massnahmen galten allgemein — nicht gruppenspezifisch.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Notverordnung ohne Parlament + Verhältnismässigkeits-Streit.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Bundesrat hatte Notkompetenz (Art. 185 Abs. 3 BV) — die Frage war nur wie weit.' } ] },
  { id: 'fcde6b1b-fb62-4a49-8220-393fe970ae49', fachbereich: 'Recht', musterlosung: 'Die drei kumulativen Voraussetzungen eines gültigen Vertrags sind: (1) Gegenseitige, übereinstimmende Willenserklärungen (OR 1), (2) Gültiger Vertragsinhalt (OR 19/20 — nicht widerrechtlich, unmöglich oder unsittlich), (3) Korrekte Vertragsform (OR 11 ff.). Fehlt auch nur eine Voraussetzung, ist der Vertrag nichtig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Handlungsfähigkeit ist Vorfrage — nicht die Vertragsvoraussetzungen selbst.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Willenserklärung + Inhalt + Form als drei kumulative Voraussetzungen.' }, { feld: 'optionen', id: 'opt-2', text: 'Schriftform und Notar sind Formvarianten — nicht die drei Grundvoraussetzungen.' }, { feld: 'optionen', id: 'opt-3', text: 'Angebot, Nachfrage, Preis sind wirtschaftliche Begriffe — nicht rechtliche Voraussetzungen.' } ] },
  { id: 'fd45879c-3b7e-40de-bf4c-575880fbbc87', fachbereich: 'Recht', musterlosung: 'Im Zivilrecht wird die Erfüllung in natura (Realerfüllung) erzwungen, sofern möglich — ein Mieter, der die Wohnung nicht verlässt, wird notfalls mit polizeilicher Hilfe ausgewiesen. Ist die Realerfüllung nicht möglich, tritt an ihre Stelle die Pflicht, Schadenersatz zu zahlen. Selbstjustiz ist ausgeschlossen (staatliches Gewaltmonopol).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Selbstjustiz — das Gewaltmonopol schliesst sie aus.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine automatische Auflösung — Durchsetzung über staatliche Organe.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Realerfüllung oder Schadenersatz durch staatliche Erzwingung.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht strafrechtlich — zivilrechtliche Streitigkeit.' } ] },
  { id: 'fe77d485-79bf-4c5b-8511-e4fd7041dff7', fachbereich: 'Recht', musterlosung: 'Drei Varianten der Unmöglichkeit: (1) Ursprüngliche/objektive Unmöglichkeit (OR 20) — Vertrag ist schon bei Abschluss nichtig; (2) Nachträgliche unverschuldete Unmöglichkeit (OR 119) — die Obligation erlischt, der Schuldner ist frei; (3) Nachträgliche verschuldete Unmöglichkeit (OR 97) — der Schuldner schuldet Schadenersatz wegen Nichterfüllung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: OR 20 (nichtig), OR 119 (Erlöschen), OR 97 (Schadenersatz).' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Schwere-Staffelung — es geht um Zeitpunkt und Verschulden.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Zeit-Staffelung als eigene Kategorie — Verschulden ist zentral.' }, { feld: 'optionen', id: 'opt-3', text: 'Das OR unterscheidet klar drei Varianten.' } ] },
  { id: 'fed0bef2-968f-4392-9100-9481c57f2b4c', fachbereich: 'Recht', musterlosung: 'Die Dispositionsmaxime besagt, dass die Parteien im Zivilprozess selbst entscheiden: ob ein Verfahren eingeleitet wird, was verlangt wird und ob das Verfahren beendet wird (z.B. durch Vergleich). Im Strafprozess gilt dagegen die Offizialmaxime — der Staat verfolgt Straftaten von Amtes wegen, unabhängig vom Willen des Opfers (bei Offizialdelikten).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das wäre Amtsermittlung — gilt nicht im Zivilprozess.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine amtliche Beweisbeschaffung — Verhandlungsmaxime.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Parteien bestimmen über Verfahrenseinleitung und -inhalt.' }, { feld: 'optionen', id: 'opt-3', text: 'Das ist Strafprozessthema — nicht Dispositionsmaxime.' } ] },
  { id: 'fee81279-3925-482e-b0b3-b8fc37f7b0f0', fachbereich: 'Recht', musterlosung: 'Grundrechte (Art. 7–34 BV) sind subjektive Rechte, die vor Gericht eingeklagt werden können — sie schützen die Individuen direkt. Sozialziele (Art. 41 BV) sind dagegen Aufträge an den Gesetzgeber, bestimmte Ziele anzustreben (z.B. soziale Sicherheit, Wohnraum). Aus Sozialzielen können Einzelne keine direkten Leistungsansprüche ableiten (Art. 41 Abs. 4 BV) — sie sind programmatisch.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Grundrechte einklagbar, Sozialziele programmatisch.' }, { feld: 'optionen', id: 'opt-1', text: 'Es gibt einen klaren Unterschied — unterschiedliche Rechtsnaturen.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Hierarchie — Grundrechte sind stärker individuell durchsetzbar.' }, { feld: 'optionen', id: 'opt-3', text: 'Beide richten sich primär an den Staat — nicht an Private.' } ] },
  { id: 'ff0aee6d-6a4b-459c-86b0-ca7cabcbcfdb', fachbereich: 'Recht', musterlosung: 'Es handelt sich um eine begrenzte Gattungsschuld: Die Flaschen sind der Gattung nach bestimmt (Bordeaux 2020), stammen aber aus einem begrenzten Vorrat (500 Flaschen im Lager). Es ist keine reine Gattungsschuld (beliebige Flaschen), weil die Auswahl beschränkt ist, und keine Stückschuld, weil nicht individuell bestimmte Flaschen geschuldet sind.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine blosse Geldschuld — es werden Flaschen geschuldet.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Begrenzte Gattungsschuld — Auswahl aus begrenztem Vorrat.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Stückschuld — die Flaschen sind nicht individuell bestimmt.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine reine Gattungsschuld — der Vorrat ist begrenzt.' } ] },
  { id: 'ff180f60-a928-43c9-9aca-e4d304dd465c', fachbereich: 'Recht', musterlosung: 'Nach Art. 257a OR müssen alle Nebenkosten, die separat abgerechnet werden sollen, einzeln im Mietvertrag aufgeführt sein — Warmwasser, Heizung, Hauswartung, Allgemeinstrom, Kabelfernsehen etc. Sind sie nicht aufgeführt, gelten sie als mit dem Mietzins abgegolten. Das schützt den Mieter vor unvorhergesehenen Zusatzkosten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Warmwasser und Heizung allein — unvollständig.' }, { feld: 'optionen', id: 'opt-1', text: 'Hauswartung allein — unvollständig.' }, { feld: 'optionen', id: 'opt-2', text: 'Allgemeinstrom allein — unvollständig.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Alle Nebenkosten einzeln aufführen (Art. 257a OR).' } ] },
  { id: 'ff6b5917-c9d1-445c-8c91-08712e0b67f8', fachbereich: 'Recht', musterlosung: 'Der Vermieter darf nur Angaben verlangen, die für die Mieterauswahl objektiv relevant sind: grundlegende Personalien, Haustiere und lärmige Tätigkeiten (Musikinstrument) sind zulässig. Fragen nach Kinderwunsch sind diskriminierend und verletzen das Datenschutzrecht sowie das Gleichbehandlungsgebot. Auch Fragen zu Nationalität, Religion oder Gewerkschaftszugehörigkeit sind unzulässig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Grundlegende Personalien sind für Vertragsabschluss nötig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Haustiere sind relevant (Tierhaltung im Mietobjekt).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Musikinstrument ist mietrechtlich relevant (Lärmpotenzial).' }, { feld: 'optionen', id: 'opt-3', text: 'Kinderwunsch ist diskriminierend — verletzt Datenschutz.' } ] },
  { id: 'ffa20ffa-4bc6-4474-a13f-ce5f2d865158', fachbereich: 'Recht', musterlosung: 'Hansli ist 16, urteilsfähig und unmündig — beschränkt handlungsunfähig (Art. 19 ZGB). Grundsätzlich braucht er die Zustimmung der Eltern. Ausnahme: geringfügige Angelegenheiten des täglichen Lebens (Art. 19 Abs. 2 ZGB). Eine CD für CHF 20 aus Taschengeld fällt darunter. Hansli darf den Kauf ohne Zustimmung tätigen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Minderjährige dürfen Geld ausgeben — in geringfügigem Rahmen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Geringfügige Angelegenheit des täglichen Lebens (Art. 19 Abs. 2 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Auch Taschengeld fällt unter die Ausnahme — nicht nur Lohn.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht jeder Kauf braucht Zustimmung — geringfügige Angelegenheiten ausgenommen.' } ] },
  // R/F-Fragen (aussagen ohne IDs → teilerklaerungen = [] nach Spec)
  { id: '027b474d-9a9b-4563-8b2e-919f8042561b', fachbereich: 'Recht', musterlosung: 'Richtig. Das Grundbuch hat nach Art. 971 ZGB eine negative Rechtskraft: Fehlt ein Eintrag, besteht grundsätzlich kein dingliches Recht an einem Grundstück. Dies gilt insbesondere für Eigentum, Dienstbarkeiten, Grundlasten und Pfandrechte. Eintragungen im engeren Sinne (Art. 958 ZGB) entstehen konstitutiv mit dem Grundbucheintrag.', teilerklaerungen: [] },
  { id: '02ffaecc-7d0d-4de2-9f81-a0c703c2c36c', fachbereich: 'Recht', musterlosung: 'Falsch. Eine verjährte Forderung besteht weiterhin als Naturalobligation (OR 127 ff.). Wer sie freiwillig bezahlt, leistet auf eine bestehende Schuld — es liegt keine ungerechtfertigte Bereicherung vor. Das Geleistete kann nicht zurückgefordert werden. Die Verjährung schliesst nur die klageweise Durchsetzung aus, nicht die Schuld selbst.', teilerklaerungen: [] },
  { id: '05f8dfca-2789-43cb-81bb-09c418b1f99a', fachbereich: 'Recht', musterlosung: 'Richtig. Der Grundsatz «Wo kein Kläger, da kein Richter» gilt im Strafprozess nur für Antragsdelikte. Bei Offizialdelikten führt die Strafverfolgungsbehörde von Amtes wegen ein Ermittlungsverfahren durch — auch ohne Strafanzeige. Ergibt sich ein hinreichender Anfangsverdacht, erhebt die Untersuchungsbehörde Anklage.', teilerklaerungen: [] },
  { id: '081c76de-3612-47c3-afd5-2aabc885f95b', fachbereich: 'Recht', musterlosung: 'Richtig. Nach OR 319 Abs. 1 ist das charakteristische Merkmal eines Arbeitsvertrags, dass der Arbeitnehmer den Weisungen des Arbeitgebers untergeordnet ist (Unterordnungsverhältnis). Die Arbeit wird unselbstständig und entgeltlich verrichtet. Dieses Merkmal unterscheidet den Arbeitsvertrag von Auftrag und Werkvertrag.', teilerklaerungen: [] },
  { id: '0e492a06-0276-4a9e-865e-70d4521523e9', fachbereich: 'Recht', musterlosung: 'Falsch. Zeugenaussagen gelten als eines der unzuverlässigeren Beweismittel, da die menschliche Wahrnehmung und Erinnerung fehleranfällig sind. Urkunden (schriftliche Dokumente) und Gutachten haben in der Regel eine höhere Beweiskraft, weil sie objektiver und nachprüfbar sind. Das Gericht würdigt alle Beweise frei (freie Beweiswürdigung).', teilerklaerungen: [] },
  { id: '1069b491-9565-4366-bdc2-6acca372c7a1', fachbereich: 'Recht', musterlosung: 'Richtig. Nach OR 336c ist eine Kündigung während einer Sperrfrist (Krankheit, Unfall, Schwangerschaft, Militärdienst) nichtig und hat keine Wirkung. Dies schützt Arbeitnehmer in vulnerablen Situationen vor Kündigung. Der Arbeitgeber muss die Kündigung nach Ablauf der Sperrfrist neu aussprechen, wenn er das Arbeitsverhältnis beenden will.', teilerklaerungen: [] },
  { id: '119a86ff-7dba-45a3-9308-b87db65c2a4b', fachbereich: 'Recht', musterlosung: 'Falsch. Nach Art. 12 Abs. 2 StGB handelt vorsätzlich, wer die Tat mit Wissen und Willen ausführt. Eine vorherige Planung ist nicht erforderlich — auch spontane, aber bewusste Taten können vorsätzlich sein. Entscheidend ist, dass der Täter den Taterfolg im Moment der Handlung will. Planung ist höchstens ein Indiz für den Vorsatz, aber keine Voraussetzung.', teilerklaerungen: [] },
]

// Duplikate filtern (defensiv)
const seen = new Set()
const filtered = updates.filter((u) => {
  if (seen.has(u.id)) return false
  seen.add(u.id)
  return true
})

const lines = filtered.map((u) => JSON.stringify(u)).join('\n') + '\n'
await fs.appendFile(OUT, lines)

const state = JSON.parse(await fs.readFile(STATE, 'utf8'))
state.letzteSession = new Date().toISOString()
state.verarbeitet = (state.verarbeitet || 0) + filtered.length
state.fragen = state.fragen || {}
for (const u of filtered) {
  state.fragen[u.id] = { status: 'done', zeitpunkt: state.letzteSession, teile: u.teilerklaerungen.length }
}
await fs.writeFile(STATE, JSON.stringify(state, null, 2))
console.log(`[s7] ${filtered.length} Updates | total ${state.verarbeitet}/${state.totalFragen}`)
